function solve(c: number, connections: number[][], queries: number[][]): number[] {
    // Build the graph
    const graph: number[][] = Array.from({ length: c + 1 }, () => []);
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // For each node, keep track of its parent in the DSU
    const parent: number[] = Array(c + 1).fill(0);
    // For each node, keep track of the minimum id in its set
    const minId: number[] = Array(c + 1).fill(0);

    // Initialize DSU
    for (let i = 1; i <= c; i++) {
        parent[i] = i;
        minId[i] = i;
    }

    // Find function with path compression
    function find(x: number): number {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Union function
    function union(x: number, y: number): boolean {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX === rootY) {
            return false;
        }
        // Merge smaller tree into larger tree
        if (minId[rootX] > minId[rootY]) {
            parent[rootX] = rootY;
            minId[rootY] = Math.min(minId[rootY], minId[rootX]);
        } else {
            parent[rootY] = rootX;
            minId[rootX] = Math.min(minId[rootX], minId[rootY]);
        }
        return true;
    }

    // Build the DSU structure based on the graph
    for (let i = 1; i <= c; i++) {
        for (const neighbor of graph[i]) {
            if (find(i) !== find(neighbor)) {
                union(i, neighbor);
            }
        }
    }

    // Process queries
    const result: number[] = [];
    const offline: boolean[] = Array(c + 1).fill(false);

    for (const [type, x] of queries) {
        if (type === 1) {
            if (offline[x]) {
                // x is offline, find the min id in its set
                const root = find(x);
                if (minId[root] === 0) {
                    result.push(-1);
                } else {
                    result.push(minId[root]);
                }
            } else {
                // x is online, itself is the answer
                result.push(x);
            }
        } else {
            // x is offline
            offline[x] = true;
        }
    }

    return result;
}

