    let mut graph: Vec<Vec<usize>> = vec![vec![]; c + 1];
    for conn in &connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        graph[u].push(v);
        graph[v].push(u);
    }

    let mut parent: Vec<usize> = vec![0; c + 1];
    let mut min_id: Vec<usize> = vec![0; c + 1];

    for i in 1..=c {
        parent[i] = i;
        min_id[i] = i;
    }

    fn find(parent: &mut Vec<usize>, x: usize) -> usize {
        if parent[x] != x {
            parent[x] = find(parent, parent[x]);
        }
        parent[x]
    }

    fn union(parent: &mut Vec<usize>, min_id: &mut Vec<usize>, x: usize, y: usize) {
        let root_x = find(parent, x);
        let root_y = find(parent, y);
